import React, { useState } from "react";

function CompareModels() {
  const [result, setResult] = useState(null);

  const sampleData = Array.from({ length: 2000 }, () => [
    Math.random(),
    Math.random(),
    Math.random()
  ]);

  const runComparison = async () => {
    const res = await fetch("http://localhost:5000/compare", {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify({ data: sampleData })
    });

    const data = await res.json();
    setResult(data);
  };

  return (
    <div style={{ textAlign: "center" }}>
      <h2>Model Comparison</h2>

      <button onClick={runComparison}>
        Compare OCSVM vs Isolation Forest
      </button>

      {result && (
        <div style={{ marginTop: "20px" }}>
          <h3>OCSVM Results</h3>
          <p>Precision: {result.ocsvm["1"].precision.toFixed(2)}</p>
          <p>Recall: {result.ocsvm["1"].recall.toFixed(2)}</p>
          <p>F1-score: {result.ocsvm["1"]["f1-score"].toFixed(2)}</p>

          <h3>Isolation Forest Results</h3>
          <p>Precision: {result.isolation_forest["1"].precision.toFixed(2)}</p>
          <p>Recall: {result.isolation_forest["1"].recall.toFixed(2)}</p>
          <p>F1-score: {result.isolation_forest["1"]["f1-score"].toFixed(2)}</p>
        </div>
      )}
    </div>
  );
}

export default CompareModels;
